CREATE TABLE IF NOT EXISTS threat_feeds (id BIGSERIAL PRIMARY KEY,name VARCHAR(120) UNIQUE NOT NULL,url VARCHAR(2048) NOT NULL,format VARCHAR(20) NOT NULL DEFAULT 'json',enabled BOOLEAN NOT NULL DEFAULT TRUE,reliability INTEGER NOT NULL DEFAULT 70 CHECK(reliability BETWEEN 0 AND 100),created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ioc_indicators (id BIGSERIAL PRIMARY KEY,type VARCHAR(20) NOT NULL,value VARCHAR(2048) NOT NULL,normalized_value VARCHAR(2048) NOT NULL,threat_type VARCHAR(100) NOT NULL DEFAULT 'unknown',confidence INTEGER NOT NULL CHECK(confidence BETWEEN 0 AND 100),severity VARCHAR(20) NOT NULL CHECK(severity IN ('low','medium','high','critical')),source VARCHAR(120) NOT NULL,tags JSONB NOT NULL DEFAULT '[]',active BOOLEAN NOT NULL DEFAULT TRUE,first_seen TIMESTAMPTZ NOT NULL DEFAULT NOW(),last_seen TIMESTAMPTZ NOT NULL DEFAULT NOW(),expires_at TIMESTAMPTZ,UNIQUE(type,normalized_value));
CREATE TABLE IF NOT EXISTS threat_intelligence_history (id BIGSERIAL PRIMARY KEY,action VARCHAR(50) NOT NULL,entity_type VARCHAR(50) NOT NULL,entity_id VARCHAR(100),details JSONB NOT NULL DEFAULT '{}',created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS feed_status (id BIGSERIAL PRIMARY KEY,feed_id BIGINT NOT NULL REFERENCES threat_feeds(id) ON DELETE CASCADE,status VARCHAR(20) NOT NULL,fetched_count INTEGER NOT NULL DEFAULT 0,accepted_count INTEGER NOT NULL DEFAULT 0,error_message TEXT,latency_ms INTEGER,checked_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS reputation_cache (id BIGSERIAL PRIMARY KEY,indicator_type VARCHAR(20) NOT NULL,value VARCHAR(2048) NOT NULL,normalized_value VARCHAR(2048) NOT NULL,score INTEGER NOT NULL CHECK(score BETWEEN 0 AND 100),verdict VARCHAR(20) NOT NULL,sources JSONB NOT NULL DEFAULT '[]',details JSONB NOT NULL DEFAULT '{}',expires_at TIMESTAMPTZ NOT NULL,updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),UNIQUE(indicator_type,normalized_value));
CREATE TABLE IF NOT EXISTS correlation_results (id BIGSERIAL PRIMARY KEY,ioc_id BIGINT NOT NULL REFERENCES ioc_indicators(id) ON DELETE CASCADE,external_event_id VARCHAR(120) NOT NULL,source_phase VARCHAR(20) NOT NULL,match_type VARCHAR(30) NOT NULL,score DOUBLE PRECISION NOT NULL,context JSONB NOT NULL DEFAULT '{}',created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),UNIQUE(ioc_id,external_event_id,source_phase));
CREATE INDEX IF NOT EXISTS ix_ioc_normalized ON ioc_indicators(normalized_value);CREATE INDEX IF NOT EXISTS ix_history_created ON threat_intelligence_history(created_at);CREATE INDEX IF NOT EXISTS ix_feed_status_checked ON feed_status(checked_at);CREATE INDEX IF NOT EXISTS ix_correlation_source ON correlation_results(source_phase);
